  1вҶ’//! Scope configuration: controls which files to analyze and which dependencies to mock.
  2вҶ’//!
  3вҶ’//! Reads a `shatter.scope.yaml` file that defines include/exclude globs for files
  4вҶ’//! and mock/passthrough globs for dependencies.
  5вҶ’
  6вҶ’use std::path::Path;
  7вҶ’
  8вҶ’use globset::{Glob, GlobSet, GlobSetBuilder};
  9вҶ’use serde::{Deserialize, Serialize};
 10вҶ’
 11вҶ’/// Error type for scope configuration operations.
 12вҶ’#[derive(Debug, thiserror::Error)]
 13вҶ’pub enum ScopeError {
 14вҶ’    #[error("failed to read scope file: {0}")]
 15вҶ’    Io(#[from] std::io::Error),
 16вҶ’
 17вҶ’    #[error("failed to parse scope YAML: {0}")]
 18вҶ’    Parse(#[from] serde_yaml::Error),
 19вҶ’
 20вҶ’    #[error("invalid glob pattern: {0}")]
 21вҶ’    InvalidPattern(#[from] globset::Error),
 22вҶ’}
 23вҶ’
 24вҶ’/// Top-level YAML structure wrapping the scope config under a `scope:` key.
 25вҶ’#[derive(Debug, Deserialize, Serialize)]
 26вҶ’struct ScopeFile {
 27вҶ’    scope: ScopeConfig,
 28вҶ’}
 29вҶ’
 30вҶ’/// Scope configuration defining which files and dependencies to include, exclude, mock, or pass through.
 31вҶ’#[derive(Debug, Clone, Deserialize, Serialize, PartialEq)]
 32вҶ’pub struct ScopeConfig {
 33вҶ’    /// Glob patterns for files to analyze.
 34вҶ’    #[serde(default)]
 35вҶ’    pub include: Vec<String>,
 36вҶ’
 37вҶ’    /// Glob patterns for files to skip.
 38вҶ’    #[serde(default)]
 39вҶ’    pub exclude: Vec<String>,
 40вҶ’
 41вҶ’    /// Glob patterns for dependencies to mock (e.g. `"node_modules/**"`).
 42вҶ’    #[serde(default)]
 43вҶ’    pub mock: Vec<String>,
 44вҶ’
 45вҶ’    /// Glob patterns for dependencies to leave as real calls (e.g. `"lodash"`).
 46вҶ’    #[serde(default)]
 47вҶ’    pub passthrough: Vec<String>,
 48вҶ’}
 49вҶ’
 50вҶ’impl Default for ScopeConfig {
 51вҶ’    fn default() -> Self {
 52вҶ’        Self {
 53вҶ’            include: vec!["**/*.ts".to_string(), "**/*.go".to_string()],
 54вҶ’            exclude: vec!["node_modules/**".to_string(), "vendor/**".to_string()],
 55вҶ’            mock: Vec::new(),
 56вҶ’            passthrough: Vec::new(),
 57вҶ’        }
 58вҶ’    }
 59вҶ’}
 60вҶ’
 61вҶ’impl ScopeConfig {
 62вҶ’    /// Read and parse a scope configuration from a YAML file.
 63вҶ’    pub fn from_file(path: &Path) -> Result<Self, ScopeError> {
 64вҶ’        let contents = std::fs::read_to_string(path)?;
 65вҶ’        let file: ScopeFile = serde_yaml::from_str(&contents)?;
 66вҶ’        Ok(file.scope)
 67вҶ’    }
 68вҶ’}
 69вҶ’
 70вҶ’/// What to do with a dependency.
 71вҶ’#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 72вҶ’pub enum DependencyAction {
 73вҶ’    /// Replace the dependency with a mock.
 74вҶ’    Mock,
 75вҶ’    /// Leave the dependency as a real call.
 76вҶ’    Passthrough,
 77вҶ’    /// No rule matched вҖ” analyze normally.
 78вҶ’    Analyze,
 79вҶ’}
 80вҶ’
 81вҶ’/// Compiled scope matcher using `GlobSet` for efficient pattern matching.
 82вҶ’pub struct ScopeMatcher {
 83вҶ’    include: GlobSet,
 84вҶ’    exclude: GlobSet,
 85вҶ’    mock: GlobSet,
 86вҶ’    passthrough: GlobSet,
 87вҶ’}
 88вҶ’
 89вҶ’impl ScopeMatcher {
 90вҶ’    /// Compile a `ScopeConfig` into a matcher.
 91вҶ’    pub fn new(config: &ScopeConfig) -> Result<Self, ScopeError> {
 92вҶ’        Ok(Self {
 93вҶ’            include: build_glob_set(&config.include)?,
 94вҶ’            exclude: build_glob_set(&config.exclude)?,
 95вҶ’            mock: build_glob_set(&config.mock)?,
 96вҶ’            passthrough: build_glob_set(&config.passthrough)?,
 97вҶ’        })
 98вҶ’    }
 99вҶ’
100вҶ’    /// Returns `true` if the path matches include patterns and does not match exclude patterns.
101вҶ’    ///
102вҶ’    /// If no include patterns are defined, all paths are considered included.
103вҶ’    pub fn is_included(&self, path: &str) -> bool {
104вҶ’        let included = self.include.is_empty() || self.include.is_match(path);
105вҶ’        let excluded = self.exclude.is_match(path);
106вҶ’        included && !excluded
107вҶ’    }
108вҶ’
109вҶ’    /// Classify a dependency symbol/path as Mock, Passthrough, or Analyze.
110вҶ’    ///
111вҶ’    /// Passthrough takes precedence over Mock (more specific override).
112вҶ’    pub fn classify_dependency(&self, symbol: &str) -> DependencyAction {
113вҶ’        if self.passthrough.is_match(symbol) {
114вҶ’            return DependencyAction::Passthrough;
115вҶ’        }
116вҶ’        if self.mock.is_match(symbol) {
117вҶ’            return DependencyAction::Mock;
118вҶ’        }
119вҶ’        DependencyAction::Analyze
120вҶ’    }
121вҶ’}
122вҶ’
123вҶ’fn build_glob_set(patterns: &[String]) -> Result<GlobSet, ScopeError> {
124вҶ’    let mut builder = GlobSetBuilder::new();
125вҶ’    for pattern in patterns {
126вҶ’        builder.add(Glob::new(pattern)?);
127вҶ’    }
128вҶ’    Ok(builder.build()?)
129вҶ’}
130вҶ’
