  1вҶ’//! Automatic mock generation for external dependencies.
  2вҶ’//!
  3вҶ’//! Classifies external dependencies into categories (I/O, library, utility)
  4вҶ’//! and generates sensible default [`MockConfig`]s without requiring user
  5вҶ’//! configuration. Users can override defaults via `.shatter/config.yaml`.
  6вҶ’
  7вҶ’use std::collections::HashMap;
  8вҶ’
  9вҶ’use serde_json::{json, Value};
 10вҶ’
 11вҶ’use crate::protocol::{ExternalDependency, MockBehavior, MockConfig};
 12вҶ’use crate::scope::{DependencyAction, ScopeMatcher};
 13вҶ’use crate::types::TypeInfo;
 14вҶ’
 15вҶ’/// Category of an external dependency, used to select default mock behavior.
 16вҶ’#[derive(Debug, Clone, Copy, PartialEq, Eq)]
 17вҶ’pub enum IoCategory {
 18вҶ’    /// File system operations (fs, path).
 19вҶ’    FileSystem,
 20вҶ’    /// Network operations (http, fetch, axios, net).
 21вҶ’    Network,
 22вҶ’    /// Database operations (pg, mysql, mongodb, redis, prisma, knex).
 23вҶ’    Database,
 24вҶ’    /// Pure utility functions (lodash, ramda, date-fns) вҖ” safe to call.
 25вҶ’    PureUtility,
 26вҶ’    /// Other external library вҖ” use type-aware stub.
 27вҶ’    ExternalOther,
 28вҶ’}
 29вҶ’
 30вҶ’/// Known module prefixes for each category.
 31вҶ’const FS_MODULES: &[&str] = &[
 32вҶ’    "fs", "node:fs", "fs/promises", "node:fs/promises", "path", "node:path",
 33вҶ’    // Go stdlib
 34вҶ’    "os", "io", "io/ioutil", "bufio",
 35вҶ’];
 36вҶ’const NETWORK_MODULES: &[&str] = &[
 37вҶ’    "http", "https", "node:http", "node:https", "net", "node:net",
 38вҶ’    "axios", "node-fetch", "fetch", "got", "superagent", "request",
 39вҶ’    "undici",
 40вҶ’];
 41вҶ’const DB_MODULES: &[&str] = &[
 42вҶ’    "pg", "mysql", "mysql2", "mongodb", "redis", "ioredis",
 43вҶ’    "prisma", "@prisma/client", "knex", "sequelize", "typeorm",
 44вҶ’    "mongoose", "sqlite3", "better-sqlite3", "drizzle-orm",
 45вҶ’    "database/sql", "gorm.io/gorm",
 46вҶ’];
 47вҶ’const PURE_UTILITY_MODULES: &[&str] = &[
 48вҶ’    "lodash", "lodash-es", "underscore", "ramda", "date-fns",
 49вҶ’    "dayjs", "moment", "validator", "uuid", "nanoid",
 50вҶ’    "chalk", "debug", "ms",
 51вҶ’    "strings", "strconv", "fmt", "math", "sort",
 52вҶ’];
 53вҶ’
 54вҶ’/// Classify an external dependency into an [`IoCategory`].
 55вҶ’pub fn classify_dependency(dep: &ExternalDependency) -> IoCategory {
 56вҶ’    let module = dep.source_module.as_str();
 57вҶ’
 58вҶ’    if FS_MODULES.iter().any(|m| module == *m || module.starts_with(&format!("{m}/"))) {
 59вҶ’        return IoCategory::FileSystem;
 60вҶ’    }
 61вҶ’    if NETWORK_MODULES.iter().any(|m| module == *m || module.starts_with(&format!("{m}/"))) {
 62вҶ’        return IoCategory::Network;
 63вҶ’    }
 64вҶ’    if DB_MODULES.iter().any(|m| module == *m || module.starts_with(&format!("{m}/"))) {
 65вҶ’        return IoCategory::Database;
 66вҶ’    }
 67вҶ’    if PURE_UTILITY_MODULES.iter().any(|m| module == *m || module.starts_with(&format!("{m}/"))) {
 68вҶ’        return IoCategory::PureUtility;
 69вҶ’    }
 70вҶ’
 71вҶ’    IoCategory::ExternalOther
 72вҶ’}
 73вҶ’
 74вҶ’/// Generate a default [`MockConfig`] for a dependency based on its category.
 75вҶ’pub fn generate_default_mock(dep: &ExternalDependency, category: IoCategory) -> MockConfig {
 76вҶ’    match category {
 77вҶ’        IoCategory::FileSystem => MockConfig {
 78вҶ’            symbol: dep.symbol.clone(),
 79вҶ’            return_values: vec![default_for_fs(&dep.symbol)],
 80вҶ’            should_track_calls: true,
 81вҶ’            default_behavior: MockBehavior::RepeatLast,
 82вҶ’        },
 83вҶ’        IoCategory::Network => MockConfig {
 84вҶ’            symbol: dep.symbol.clone(),
 85вҶ’            return_values: vec![json!({"status": 200, "data": {}})],
 86вҶ’            should_track_calls: true,
 87вҶ’            default_behavior: MockBehavior::RepeatLast,
 88вҶ’        },
 89вҶ’        IoCategory::Database => MockConfig {
 90вҶ’            symbol: dep.symbol.clone(),
 91вҶ’            return_values: vec![default_for_db(&dep.symbol)],
 92вҶ’            should_track_calls: true,
 93вҶ’            default_behavior: MockBehavior::RepeatLast,
 94вҶ’        },
 95вҶ’        IoCategory::PureUtility => MockConfig {
 96вҶ’            symbol: dep.symbol.clone(),
 97вҶ’            return_values: vec![],
 98вҶ’            should_track_calls: false,
 99вҶ’            default_behavior: MockBehavior::Passthrough,
100вҶ’        },
101вҶ’        IoCategory::ExternalOther => MockConfig {
102вҶ’            symbol: dep.symbol.clone(),
103вҶ’            return_values: vec![default_for_type(&dep.return_type)],
104вҶ’            should_track_calls: true,
105вҶ’            default_behavior: MockBehavior::RepeatLast,
106вҶ’        },
107вҶ’    }
108вҶ’}
109вҶ’
110вҶ’/// Pick a sensible default for a file-system operation based on the symbol name.
111вҶ’fn default_for_fs(symbol: &str) -> Value {
112вҶ’    let lower = symbol.to_lowercase();
113вҶ’    if lower.contains("read") {
114вҶ’        json!("")
115вҶ’    } else if lower.contains("stat") || lower.contains("lstat") {
116вҶ’        json!({"size": 0, "isFile": true, "isDirectory": false})
117вҶ’    } else if lower.contains("exists") {
118вҶ’        json!(true)
119вҶ’    } else if lower.contains("readdir") || lower.contains("glob") {
120вҶ’        json!([])
121вҶ’    } else {
122вҶ’        // write, mkdir, unlink, etc. вҖ” return undefined/null (success)
123вҶ’        Value::Null
124вҶ’    }
125вҶ’}
126вҶ’
127вҶ’/// Pick a sensible default for a database operation based on the symbol name.
128вҶ’fn default_for_db(symbol: &str) -> Value {
129вҶ’    let lower = symbol.to_lowercase();
130вҶ’    if lower.contains("query") || lower.contains("find") || lower.contains("select") || lower.contains("all") {
131вҶ’        json!({"rows": []})
132вҶ’    } else if lower.contains("insert") || lower.contains("create") || lower.contains("save") {
133вҶ’        json!({"rowCount": 1})
134вҶ’    } else if lower.contains("update") || lower.contains("delete") || lower.contains("remove") {
135вҶ’        json!({"rowCount": 0})
136вҶ’    } else {
137вҶ’        Value::Null
138вҶ’    }
139вҶ’}
140вҶ’
141вҶ’/// Generate a type-appropriate default value from TypeInfo.
142вҶ’fn default_for_type(typ: &TypeInfo) -> Value {
143вҶ’    match typ {
144вҶ’        TypeInfo::Int => json!(0),
145вҶ’        TypeInfo::Float => json!(0.0),
146вҶ’        TypeInfo::Str => json!(""),
147вҶ’        TypeInfo::Bool => json!(false),
148вҶ’        TypeInfo::Array { .. } => json!([]),
149вҶ’        TypeInfo::Object { fields } => {
150вҶ’            let mut obj = serde_json::Map::new();
151вҶ’            for (name, field_type) in fields {
152вҶ’                obj.insert(name.clone(), default_for_type(field_type));
153вҶ’            }
154вҶ’            Value::Object(obj)
155вҶ’        }
156вҶ’        TypeInfo::Nullable { .. } => Value::Null,
157вҶ’        TypeInfo::Union { variants } => {
158вҶ’            if let Some(first) = variants.first() {
159вҶ’                default_for_type(first)
160вҶ’            } else {
161вҶ’                Value::Null
162вҶ’            }
163вҶ’        }
164вҶ’        TypeInfo::Complex { .. } | TypeInfo::Opaque { .. } | TypeInfo::Unknown => Value::Null,
165вҶ’    }
166вҶ’}
167вҶ’
168вҶ’/// User-provided mock override from `.shatter/config.yaml`.
169вҶ’#[derive(Debug, Clone, PartialEq, serde::Deserialize, serde::Serialize)]
170вҶ’pub struct MockOverride {
171вҶ’    /// Pre-configured return values, replacing auto-generated defaults.
172вҶ’    #[serde(default)]
173вҶ’    pub return_values: Option<Vec<Value>>,
174вҶ’    /// Override the default behavior.
175вҶ’    #[serde(default)]
176вҶ’    pub behavior: Option<MockBehavior>,
177вҶ’}
178вҶ’
179вҶ’/// Generate auto-mocks for all dependencies of a function.
180вҶ’///
181вҶ’/// Returns mock configs for dependencies that:
182вҶ’/// 1. Are not already covered by `existing_mocks` (e.g., behavior-map mocks)
183вҶ’/// 2. Are classified as Mock (not Passthrough or Analyze) by the scope matcher
184вҶ’///
185вҶ’/// User overrides from config take precedence over auto-generated defaults.
186вҶ’pub fn generate_auto_mocks(
187вҶ’    deps: &[ExternalDependency],
188вҶ’    scope: Option<&ScopeMatcher>,
189вҶ’    overrides: &HashMap<String, MockOverride>,
190вҶ’    existing_mocks: &[MockConfig],
191вҶ’) -> Vec<MockConfig> {
192вҶ’    let already_mocked: std::collections::HashSet<&str> = existing_mocks
193вҶ’        .iter()
194вҶ’        .map(|m| m.symbol.as_str())
195вҶ’        .collect();
196вҶ’
197вҶ’    let mut result = Vec::new();
198вҶ’
199вҶ’    for dep in deps {
200вҶ’        // Skip if already covered by a behavior-map mock
201вҶ’        if already_mocked.contains(dep.symbol.as_str()) {
202вҶ’            continue;
203вҶ’        }
204вҶ’
205вҶ’        // Check scope: if Passthrough, skip; if Analyze (no rule), use category logic
206вҶ’        if let Some(matcher) = scope {
207вҶ’            match matcher.classify_dependency(&dep.symbol) {
208вҶ’                DependencyAction::Passthrough => continue,
209вҶ’                DependencyAction::Mock | DependencyAction::Analyze => {}
210вҶ’            }
211вҶ’        }
212вҶ’
213вҶ’        let category = classify_dependency(dep);
214вҶ’
215вҶ’        // Pure utilities default to passthrough вҖ” skip generating a mock
216вҶ’        if category == IoCategory::PureUtility && !overrides.contains_key(&dep.symbol) {
217вҶ’            continue;
218вҶ’        }
219вҶ’
220вҶ’        let mut mock = generate_default_mock(dep, category);
221вҶ’
222вҶ’        // Apply user overrides
223вҶ’        if let Some(ov) = overrides.get(&dep.symbol) {
224вҶ’            if let Some(ref vals) = ov.return_values {
225вҶ’                mock.return_values = vals.clone();
226вҶ’            }
227вҶ’            if let Some(ref behavior) = ov.behavior {
228вҶ’                mock.default_behavior = behavior.clone();
229вҶ’            }
230вҶ’        }
231вҶ’
232вҶ’        result.push(mock);
233вҶ’    }
234вҶ’
235вҶ’    result
236вҶ’}
