433вҶ’
434вҶ’        // User override: custom return value for the database query mock
435вҶ’        let mut overrides = HashMap::new();
436вҶ’        overrides.insert(
437вҶ’            "query".to_string(),
438вҶ’            MockOverride {
439вҶ’                return_values: Some(vec![json!({"rows": [{"id": 1, "name": "alice"}]})]),
