441вҶ’            },
442вҶ’        );
443вҶ’
444вҶ’        let mocks = generate_auto_mocks(&deps, None, &overrides, &[]);
445вҶ’
446вҶ’        // 4 mocks generated: fs, network, db (overridden), and external other.
447вҶ’        // lodash (pure utility) is skipped.
448вҶ’        assert_eq!(mocks.len(), 4, "expected 4 mocks (lodash skipped)");
449вҶ’
450вҶ’        let by_symbol: HashMap<&str, &MockConfig> =
451вҶ’            mocks.iter().map(|m| (m.symbol.as_str(), m)).collect();
