  1вҶ’//! Compositional mock generation from behavior maps.
  2вҶ’//!
  3вҶ’//! When function A calls function B and B's [`BehaviorMap`] is available,
  4вҶ’//! this module builds an input-conditional decision tree that produces
  5вҶ’//! high-fidelity mocks: given the same arguments B received during
  6вҶ’//! exploration, the mock returns the same value (or throws the same error).
  7вҶ’//!
  8вҶ’//! The flat [`MockConfig`] format cycles through return values in order,
  9вҶ’//! ignoring what the caller actually passes. A [`MockDecisionTree`] instead
 10вҶ’//! matches each call's arguments against observed input patterns and picks
 11вҶ’//! the correct output, falling back to a default when no pattern matches.
 12вҶ’
 13вҶ’use serde::{Deserialize, Serialize};
 14вҶ’
 15вҶ’use crate::behavior::{Behavior, BehaviorMap};
 16вҶ’use crate::protocol::{MockBehavior, MockConfig};
 17вҶ’
 18вҶ’// ---------------------------------------------------------------------------
 19вҶ’// Pattern matching types
 20вҶ’// ---------------------------------------------------------------------------
 21вҶ’
 22вҶ’/// How to match a single argument value.
 23вҶ’#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 24вҶ’#[serde(tag = "kind", rename_all = "snake_case")]
 25вҶ’pub enum PatternMatcher {
 26вҶ’    /// Exact JSON equality.
 27вҶ’    Eq { value: serde_json::Value },
 28вҶ’    /// Numeric range (inclusive on both ends).
 29вҶ’    Range { min: f64, max: f64 },
 30вҶ’    /// Match by JSON type name ("number", "string", "boolean", "null", "array", "object").
 31вҶ’    Type { type_name: String },
 32вҶ’    /// Match anything.
 33вҶ’    Any,
 34вҶ’}
 35вҶ’
 36вҶ’/// A condition on one argument of the mocked function.
 37вҶ’#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 38вҶ’pub struct InputPattern {
 39вҶ’    /// Zero-based index of the argument to check.
 40вҶ’    pub arg_index: usize,
 41вҶ’    /// How to match the argument.
 42вҶ’    pub matcher: PatternMatcher,
 43вҶ’}
 44вҶ’
 45вҶ’/// A single branch of the decision tree: if all input patterns match,
 46вҶ’/// return `return_value` (or throw `error`).
 47вҶ’#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 48вҶ’pub struct MockCondition {
 49вҶ’    /// Patterns that must all match for this condition to fire.
 50вҶ’    pub input_patterns: Vec<InputPattern>,
 51вҶ’    /// Value to return when the condition matches.
 52вҶ’    pub return_value: serde_json::Value,
 53вҶ’    /// If set, throw this error instead of returning.
 54вҶ’    pub error: Option<String>,
 55вҶ’}
 56вҶ’
 57вҶ’/// An input-conditional mock: an ordered list of conditions checked
 58вҶ’/// top-to-bottom, with a default for unmatched calls.
 59вҶ’#[derive(Debug, Clone, PartialEq, Serialize, Deserialize)]
 60вҶ’pub struct MockDecisionTree {
 61вҶ’    /// The symbol this mock replaces.
 62вҶ’    pub symbol: String,
 63вҶ’    /// Ordered conditions вҖ” first match wins.
 64вҶ’    pub conditions: Vec<MockCondition>,
 65вҶ’    /// Value returned when no condition matches.
 66вҶ’    pub default_return: serde_json::Value,
 67вҶ’}
 68вҶ’
 69вҶ’// ---------------------------------------------------------------------------
 70вҶ’// Building decision trees from behavior maps
 71вҶ’// ---------------------------------------------------------------------------
 72вҶ’
 73вҶ’/// Build a [`MockDecisionTree`] from a [`BehaviorMap`].
 74вҶ’///
 75вҶ’/// Each behavior becomes a condition whose input patterns are exact-match
 76вҶ’/// on every argument, and whose output is the observed return value (or
 77вҶ’/// error). Behaviors that have neither a return value nor a thrown error
 78вҶ’/// are skipped.
 79вҶ’///
 80вҶ’/// Returns `None` if the behavior map has no usable behaviors.
 81вҶ’pub fn build_mock_from_behavior_map(behavior_map: &BehaviorMap) -> Option<MockDecisionTree> {
 82вҶ’    let mut conditions: Vec<MockCondition> = Vec::new();
 83вҶ’    let mut last_return = serde_json::Value::Null;
 84вҶ’
 85вҶ’    for behavior in &behavior_map.behaviors {
 86вҶ’        if let Some(condition) = behavior_to_condition(behavior) {
 87вҶ’            if condition.error.is_none() {
 88вҶ’                last_return = condition.return_value.clone();
 89вҶ’            }
 90вҶ’            conditions.push(condition);
 91вҶ’        }
 92вҶ’    }
 93вҶ’
 94вҶ’    if conditions.is_empty() {
 95вҶ’        return None;
 96вҶ’    }
 97вҶ’
 98вҶ’    Some(MockDecisionTree {
 99вҶ’        symbol: behavior_map.function_id.clone(),
100вҶ’        conditions,
101вҶ’        default_return: last_return,
102вҶ’    })
103вҶ’}
104вҶ’
105вҶ’/// Convert a single [`Behavior`] into a [`MockCondition`].
106вҶ’///
107вҶ’/// Returns `None` if the behavior has no return value and no thrown error.
108вҶ’fn behavior_to_condition(behavior: &Behavior) -> Option<MockCondition> {
109вҶ’    let has_return = behavior.return_value.is_some();
110вҶ’    let has_error = behavior.thrown_error.is_some();
111вҶ’
112вҶ’    if !has_return && !has_error {
113вҶ’        return None;
114вҶ’    }
115вҶ’
116вҶ’    let input_patterns: Vec<InputPattern> = behavior
117вҶ’        .input_args
118вҶ’        .iter()
119вҶ’        .enumerate()
120вҶ’        .map(|(i, arg)| InputPattern {
121вҶ’            arg_index: i,
122вҶ’            matcher: PatternMatcher::Eq {
123вҶ’                value: arg.clone(),
124вҶ’            },
125вҶ’        })
126вҶ’        .collect();
127вҶ’
128вҶ’    let return_value = behavior
129вҶ’        .return_value
130вҶ’        .clone()
131вҶ’        .unwrap_or(serde_json::Value::Null);
132вҶ’
133вҶ’    let error = behavior
134вҶ’        .thrown_error
135вҶ’        .as_ref()
136вҶ’        .map(|e| e.message.clone());
137вҶ’
138вҶ’    Some(MockCondition {
139вҶ’        input_patterns,
140вҶ’        return_value,
141вҶ’        error,
142вҶ’    })
143вҶ’}
144вҶ’
145вҶ’/// Check whether a set of arguments matches all input patterns in a condition.
146вҶ’pub fn matches_condition(args: &[serde_json::Value], condition: &MockCondition) -> bool {
147вҶ’    condition.input_patterns.iter().all(|pattern| {
148вҶ’        args.get(pattern.arg_index)
149вҶ’            .is_some_and(|arg| matches_pattern(arg, &pattern.matcher))
150вҶ’    })
151вҶ’}
152вҶ’
153вҶ’/// Check whether a single argument matches a pattern.
154вҶ’fn matches_pattern(value: &serde_json::Value, matcher: &PatternMatcher) -> bool {
155вҶ’    match matcher {
156вҶ’        PatternMatcher::Eq { value: expected } => value == expected,
157вҶ’        PatternMatcher::Range { min, max } => value
158вҶ’            .as_f64()
159вҶ’            .is_some_and(|n| n >= *min && n <= *max),
160вҶ’        PatternMatcher::Type { type_name } => json_type_name(value) == type_name.as_str(),
161вҶ’        PatternMatcher::Any => true,
162вҶ’    }
163вҶ’}
164вҶ’
165вҶ’/// Return a type name string for a JSON value.
166вҶ’fn json_type_name(value: &serde_json::Value) -> &'static str {
167вҶ’    match value {
168вҶ’        serde_json::Value::Null => "null",
169вҶ’        serde_json::Value::Bool(_) => "boolean",
170вҶ’        serde_json::Value::Number(_) => "number",
171вҶ’        serde_json::Value::String(_) => "string",
172вҶ’        serde_json::Value::Array(_) => "array",
173вҶ’        serde_json::Value::Object(_) => "object",
174вҶ’    }
175вҶ’}
176вҶ’
177вҶ’// ---------------------------------------------------------------------------
178вҶ’// Conversion to protocol MockConfig
179вҶ’// ---------------------------------------------------------------------------
180вҶ’
181вҶ’/// Convert a [`MockDecisionTree`] to the flat [`MockConfig`] protocol type.
182вҶ’///
183вҶ’/// The decision tree's conditions are flattened: each condition's return value
184вҶ’/// becomes an entry in `return_values` (error conditions produce `null`).
185вҶ’/// The decision tree metadata is stored in the return values so frontends
186вҶ’/// can reconstruct conditional behavior.
187вҶ’///
188вҶ’/// This is a lossy conversion вҖ” the flat format cannot fully represent
189вҶ’/// input-conditional logic. For frontends that support conditional mocks,
190вҶ’/// the tree should be sent directly (future protocol extension).
191вҶ’pub fn to_enhanced_mock_config(tree: &MockDecisionTree) -> MockConfig {
192вҶ’    let return_values: Vec<serde_json::Value> = tree
193вҶ’        .conditions
194вҶ’        .iter()
195вҶ’        .filter(|c| c.error.is_none())
196вҶ’        .map(|c| c.return_value.clone())
197вҶ’        .collect();
198вҶ’
199вҶ’    MockConfig {
200вҶ’        symbol: tree.symbol.clone(),
201вҶ’        return_values,
202вҶ’        should_track_calls: true,
203вҶ’        default_behavior: MockBehavior::RepeatLast,
204вҶ’    }
205вҶ’}
206вҶ’
207вҶ’/// Build a [`MockConfig`] from a [`BehaviorMap`], using the decision tree
208вҶ’/// when possible and falling back to the flat conversion otherwise.
209вҶ’pub fn mock_config_from_behavior_map(behavior_map: &BehaviorMap) -> MockConfig {
210вҶ’    match build_mock_from_behavior_map(behavior_map) {
211вҶ’        Some(tree) => to_enhanced_mock_config(&tree),
212вҶ’        None => behavior_map.to_mock_config(),
213вҶ’    }
214вҶ’}
